import{_ as e,o as l,c as i,ae as r}from"./chunks/framework.DDBOLhwZ.js";const q=JSON.parse('{"title":"GetSeed 常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"getseed/faq.md","filePath":"getseed/faq.md"}'),t={name:"getseed/faq.md"};function h(o,a,d,n,s,u){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="getseed-常见问题" tabindex="-1">GetSeed 常见问题 <a class="header-anchor" href="#getseed-常见问题" aria-label="Permalink to &quot;GetSeed 常见问题&quot;">​</a></h1><h2 id="连接问题" tabindex="-1">连接问题 <a class="header-anchor" href="#连接问题" aria-label="Permalink to &quot;连接问题&quot;">​</a></h2><h3 id="搜索不到设备" tabindex="-1">搜索不到设备？ <a class="header-anchor" href="#搜索不到设备" aria-label="Permalink to &quot;搜索不到设备？&quot;">​</a></h3><ul><li>确认蓝牙已开启</li><li>iOS：设置→Get笔记→启用蓝牙</li><li>Android：启用蓝牙和位置权限</li><li>短按MARK键1秒开启设备</li><li>设备没亮白灯请先充电10分钟</li></ul><h3 id="连接不上" tabindex="-1">连接不上？ <a class="header-anchor" href="#连接不上" aria-label="Permalink to &quot;连接不上？&quot;">​</a></h3><ul><li>确保卡片有电，APP升级到2.4.3+</li><li>长按MARK键1秒唤醒（3小时会休眠）</li><li>鸿蒙：先在系统蓝牙配对</li><li>iOS/华为：如从系统蓝牙连接过，需先&quot;忽略此设备&quot;</li></ul><h2 id="使用问题" tabindex="-1">使用问题 <a class="header-anchor" href="#使用问题" aria-label="Permalink to &quot;使用问题&quot;">​</a></h2><h3 id="能录手机通话吗" tabindex="-1">能录手机通话吗？ <a class="header-anchor" href="#能录手机通话吗" aria-label="Permalink to &quot;能录手机通话吗？&quot;">​</a></h3><p>支持！电话、微信视频、腾讯/钉钉/飞书会议全能录。 自动识别切换现场/通话录音模式。</p><h3 id="戴蓝牙耳机能录吗" tabindex="-1">戴蓝牙耳机能录吗？ <a class="header-anchor" href="#戴蓝牙耳机能录吗" aria-label="Permalink to &quot;戴蓝牙耳机能录吗？&quot;">​</a></h3><p>不支持，无法获取蓝牙耳机播放的声音。</p><h3 id="能脱离手机使用吗" tabindex="-1">能脱离手机使用吗？ <a class="header-anchor" href="#能脱离手机使用吗" aria-label="Permalink to &quot;能脱离手机使用吗？&quot;">​</a></h3><p>可以，离线录音后连接APP自动同步。</p><h3 id="防水吗" tabindex="-1">防水吗？ <a class="header-anchor" href="#防水吗" aria-label="Permalink to &quot;防水吗？&quot;">​</a></h3><p>不防水，避免接触液体。</p><h2 id="充电问题" tabindex="-1">充电问题 <a class="header-anchor" href="#充电问题" aria-label="Permalink to &quot;充电问题&quot;">​</a></h2><h3 id="充满要多久" tabindex="-1">充满要多久？ <a class="header-anchor" href="#充满要多久" aria-label="Permalink to &quot;充满要多久？&quot;">​</a></h3><p>约1.5小时从0到100%。</p><h3 id="充电时能录音吗" tabindex="-1">充电时能录音吗？ <a class="header-anchor" href="#充电时能录音吗" aria-label="Permalink to &quot;充电时能录音吗？&quot;">​</a></h3><p>不能。录音中去充电不影响录音但无法充电。</p><h3 id="续航多久" tabindex="-1">续航多久？ <a class="header-anchor" href="#续航多久" aria-label="Permalink to &quot;续航多久？&quot;">​</a></h3><p>连续录音35小时，待机60天。</p><h2 id="发芽功能" tabindex="-1">发芽功能 <a class="header-anchor" href="#发芽功能" aria-label="Permalink to &quot;发芽功能&quot;">​</a></h2><h3 id="发芽是什么" tabindex="-1">发芽是什么？ <a class="header-anchor" href="#发芽是什么" aria-label="Permalink to &quot;发芽是什么？&quot;">​</a></h3><p>AI基于录音笔记进行扩展联想，找出相关名言、类似观点。</p><h3 id="使用规则" tabindex="-1">使用规则 <a class="header-anchor" href="#使用规则" aria-label="Permalink to &quot;使用规则&quot;">​</a></h3><ul><li>每天5次机会，0点重置</li><li>需要先有新录音笔记</li><li>生成约3-5分钟</li></ul><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><h3 id="隐私保障" tabindex="-1">隐私保障？ <a class="header-anchor" href="#隐私保障" aria-label="Permalink to &quot;隐私保障？&quot;">​</a></h3><ul><li>笔记默认只有自己可见</li><li>数据严格加密隔离存储</li><li>硬件级防护，严禁外设导出</li></ul><h3 id="会员到期还能用吗" tabindex="-1">会员到期还能用吗？ <a class="header-anchor" href="#会员到期还能用吗" aria-label="Permalink to &quot;会员到期还能用吗？&quot;">​</a></h3><p>可以继续录音。区别在于转写时长：</p><ul><li>免费用户：600分钟/月</li><li>PRO会员：无限制</li></ul>',33)])])}const b=e(t,[["render",h]]);export{q as __pageData,b as default};
